exports.up = (pgm) => {
  const rows = questions.map((q) => {
    return `(${n(q.item_number)}, ${e(q.thematic_area)}, ${e(q.requirement)}, ${n(q.bcbs_principle_number)}, ${e(q.bcbs_principle_name)}, ${e(q.ecb_reference)}, ${e(q.expectations)}, ${e(q.score_1_desc)}, ${e(q.score_2_desc)}, ${e(q.score_3_desc)}, ${e(q.score_4_desc)}, ${e(q.respondents_hint)}, ${e(q.supportive_material)}, ${e(q.related_kpis)})`;
  });

  pgm.sql(`
    INSERT INTO questions (
      item_number, thematic_area, requirement,
      bcbs_principle_number, bcbs_principle_name,
      ecb_reference, expectations,
      score_1_desc, score_2_desc, score_3_desc, score_4_desc,
      respondents_hint, supportive_material, related_kpis
    ) VALUES
    ${rows.join(',\n    ')}
    ON CONFLICT (item_number) DO NOTHING;
  `);
};

exports.down = (pgm) => {
  pgm.sql(`DELETE FROM questions WHERE item_number BETWEEN 1 AND 40;`);
};
